423→): Promise<OrchestratorSessionResult> {
424→  const adapter = input.adapter;
425→  const repoRoot = validation.repoPath;
426→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
427→
428→  // 1. Create worktree for isolated agent work
429→  const worktreeResult = await createWorktree(
430→    input.shellExec,
431→    repoRoot,
432→    taskSlug,
433→  );
434→
435→  if (!worktreeResult.ok) {
436→    return {
437→      ok: false,
438→      error: worktreeError(worktreeResult.error.message),
439→    };
440→  }
441→
442→  const { branchName, worktreePath } = worktreeResult.value;
443→
444→  // 2. Create agent_session record
445→  const { session_id: agentSessionId } = await input.createAgentSession({
446→    surreal: input.surreal,
447→    agent: input.agentName ?? "claude",
448→    workspaceRecord: validation.workspaceRecord,
449→    taskId: input.taskId,
450→  });
451→
452→  const streamId = generateStreamId(agentSessionId);
453→
454→  // 3. Create session via adapter — agent works in worktree, not main repo
455→  let handle: SessionHandle;
456→  try {
457→    await adapter.setMcpConfig(worktreePath, "brain", {
458→      type: "remote",
459→      url: `${input.brainBaseUrl}/mcp/agent/${agentSessionId}`,
460→      headers: { "X-Brain-Auth": input.mcpAuthToken },
461→    });
462→
463→    handle = await adapter.createSession({
464→      agent: input.sandboxAgentType ?? "claude",
465→      cwd: worktreePath,
466→      ...(input.env ? { env: input.env } : {}),
467→    });
468→  } catch (err) {
469→    // Rollback: remove worktree and delete agent_session on adapter failure
470→    await removeWorktree(input.shellExec, repoRoot, branchName);
471→    const sessionRecord = new RecordId("agent_session", agentSessionId);
472→    await input.surreal.delete(sessionRecord);
473→    return {
474→      ok: false,
475→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
476→    };
477→  }
478→
479→  // 4. Update agent_session with sandbox + worktree fields
480→  const sessionRecord = new RecordId("agent_session", agentSessionId);
481→  await input.surreal.update(sessionRecord).merge({
482→    orchestrator_status: "spawning" as OrchestratorStatus,
483→    stream_id: streamId,
484→    session_type: "sandbox_agent",
485→    provider: "local",
486→    external_session_id: handle.id,
487→    worktree_branch: branchName,
488→    worktree_path: worktreePath,
489→  });
490→
491→  // 5. Transition intent to executing
492→  if (input.intentId) {
493→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
494→  }
495→
496→  return {
497→    ok: true,
498→    value: {
499→      agentSessionId,
500→      streamId,
501→      worktreeBranch: branchName,
502→      sessionHandle: handle,
503→    },
504→  };
505→}
