540→// ---------------------------------------------------------------------------
541→// abortOrchestratorSession
542→// ---------------------------------------------------------------------------
543→
544→type AbortSessionInput = {
545→  surreal: Surreal;
546→  shellExec: ShellExec;
547→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
548→  sessionId: string;
549→  adapter?: SandboxAgentAdapter;
550→  endAgentSession: (input: {
551→    surreal: Surreal;
552→    workspaceRecord: RecordId<"workspace", string>;
553→    sessionId: string;
554→    summary: string;
555→  }) => Promise<{ session_id: string; ended: boolean }>;
556→};
557→
558→export async function abortOrchestratorSession(
559→  input: AbortSessionInput,
560→): Promise<AbortSessionResult> {
561→  const lookup = await lookupSession(input.surreal, input.sessionId);
562→  if (!lookup.ok) {
563→    return { ok: false, error: lookup.error };
564→  }
565→  const { session, record: sessionRecord } = lookup;
566→
567→  // 1. Destroy the sandbox agent session
568→  if (session.external_session_id && input.adapter) {
569→    try {
570→      await input.adapter.destroySession(session.external_session_id);
571→    } catch (err) {
572→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
573→        sessionId: input.sessionId,
574→        externalSessionId: session.external_session_id,
575→        error: String(err),
576→      });
577→    }
578→  }
579→
580→  // 2. Update orchestrator_status to aborted
581→  await input.surreal.update(sessionRecord).merge({
582→    orchestrator_status: "aborted" as OrchestratorStatus,
583→  });
584→
585→  const workspaceRecord = requireWorkspace(session, input.sessionId);
586→
587→  // 3. Remove worktree if branch name exists
588→  if (session.worktree_branch) {
589→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
590→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
591→  }
592→
593→  // 4. Return task to ready
594→  if (session.task_id) {
595→    await input.surreal.update(session.task_id).merge({
596→      status: "ready",
597→      updated_at: new Date(),
598→    });
599→  }
600→
601→  // 5. End the agent session
602→  await input.endAgentSession({
603→    surreal: input.surreal,
604→    workspaceRecord,
605→    sessionId: input.sessionId,
606→    summary: "Session aborted",
607→  });
608→
609→  return {
610→    ok: true,
611→    value: {
612→      aborted: true,
613→      sessionId: input.sessionId,
614→    },
615→  };
616→}
