619→// acceptOrchestratorSession
620→// ---------------------------------------------------------------------------
621→
622→type AcceptSessionInput = {
623→  surreal: Surreal;
624→  shellExec: ShellExec;
625→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
626→  sessionId: string;
627→  summary: string;
628→  adapter?: SandboxAgentAdapter;
629→  endAgentSession: (input: {
630→    surreal: Surreal;
631→    workspaceRecord: RecordId<"workspace", string>;
632→    sessionId: string;
633→    summary: string;
634→  }) => Promise<{ session_id: string; ended: boolean }>;
635→};
636→
637→export async function acceptOrchestratorSession(
638→  input: AcceptSessionInput,
639→): Promise<AcceptSessionResult> {
640→  const lookup = await lookupSession(input.surreal, input.sessionId);
641→  if (!lookup.ok) {
642→    return { ok: false, error: lookup.error };
643→  }
644→  const { session, record: sessionRecord, status } = lookup;
645→
646→  if (!ACCEPTABLE_STATUSES.has(status)) {
647→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
648→  }
649→
650→  const workspaceRecord = requireWorkspace(session, input.sessionId);
651→
652→  // 1. Destroy the sandbox agent session
653→  if (session.external_session_id && input.adapter) {
654→    try {
655→      await input.adapter.destroySession(session.external_session_id);
656→    } catch (err) {
657→      log.warn("orchestrator.accept", "Failed to destroy sandbox session", {
658→        sessionId: input.sessionId,
659→        externalSessionId: session.external_session_id,
660→        error: String(err),
661→      });
662→    }
663→  }
664→
665→  // 2. Update orchestrator_status to completed
666→  await input.surreal.update(sessionRecord).merge({
667→    orchestrator_status: "completed" as OrchestratorStatus,
668→  });
669→
670→  // 3. Remove worktree (branch is preserved for merge/review)
671→  if (session.worktree_branch) {
672→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
673→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
674→  }
675→
676→  // 4. End the agent session
677→  await input.endAgentSession({
678→    surreal: input.surreal,
679→    workspaceRecord,
680→    sessionId: input.sessionId,
681→    summary: input.summary,
682→  });
683→
684→  return {
685→    ok: true,
686→    value: {
687→      accepted: true,
688→      sessionId: input.sessionId,
689→    },
690→  };
691→}
