693→// ---------------------------------------------------------------------------
694→// State guard helpers
695→// ---------------------------------------------------------------------------
696→
697→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
698→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
699→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
700→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
701→
702→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
703→  return {
704→    code: "SESSION_ERROR",
705→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
706→    httpStatus: 409,
707→  };
708→}
709→
710→function sessionAborted(sessionId: string): SessionError {
711→  return {
712→    code: "SESSION_ERROR",
713→    message: `Session ${sessionId} has been aborted`,
714→    httpStatus: 409,
715→  };
716→}
717→
718→// ---------------------------------------------------------------------------
719→// getOrchestratorReview
720→// ---------------------------------------------------------------------------
721→
722→type GetReviewInput = {
723→  surreal: Surreal;
724→  sessionId: string;
725→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
726→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
727→  getTaskTitle: (taskId: string) => Promise<string>;
728→};
729→
730→export async function getOrchestratorReview(
731→  input: GetReviewInput,
732→): Promise<ReviewResult> {
733→  const lookup = await lookupSession(input.surreal, input.sessionId);
734→  if (!lookup.ok) {
735→    return { ok: false, error: lookup.error };
736→  }
737→  const { session, status } = lookup;
738→
739→  if (status === "aborted") {
740→    return { ok: false, error: sessionAborted(input.sessionId) };
741→  }
742→
743→  if (!REVIEWABLE_STATUSES.has(status)) {
744→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
745→  }
746→
747→  // Get diff from the branch
748→  const branchName = session.worktree_branch ?? "";
749→  const workspaceRecord = requireWorkspace(session, input.sessionId);
750→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
751→  const diffResult = await input.getDiff(repoRoot, branchName);
752→
753→  const diff = diffResult.ok
754→    ? diffResult.value
755→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
756→
757→  // Get task title
758→  const taskId = session.task_id ? session.task_id.id : "";
759→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
760→
761→  return {
762→    ok: true,
763→    value: {
764→      taskTitle,
765→      diff,
766→      session: {
767→        orchestratorStatus: status,
768→        ...pickDefined({
769→          worktreeBranch: session.worktree_branch,
770→          startedAt: session.started_at,
771→          lastEventAt: session.last_event_at,
772→        }),
773→      },
774→    },
775→  };
776→}
