778→// ---------------------------------------------------------------------------
779→// rejectOrchestratorSession
780→// ---------------------------------------------------------------------------
781→
782→type RejectSessionInput = {
783→  surreal: Surreal;
784→  sessionId: string;
785→  feedback: string;
786→};
787→
788→export async function rejectOrchestratorSession(
789→  input: RejectSessionInput,
790→): Promise<RejectSessionResult> {
791→  const lookup = await lookupSession(input.surreal, input.sessionId);
792→  if (!lookup.ok) {
793→    return { ok: false, error: lookup.error };
794→  }
795→  const { session, record: sessionRecord, status } = lookup;
796→
797→  if (!REJECTABLE_STATUSES.has(status)) {
798→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
799→  }
800→
801→  // 1. Update session status to active (agent resumes work)
802→  await input.surreal.update(sessionRecord).merge({
803→    orchestrator_status: "active" as OrchestratorStatus,
804→    last_feedback: input.feedback,
805→  });
806→
807→  // 2. Return task to in_progress
808→  if (session.task_id) {
809→    await input.surreal.update(session.task_id).merge({
810→      status: "in_progress",
811→      updated_at: new Date(),
812→    });
813→  }
814→
815→  return {
816→    ok: true,
817→    value: {
818→      rejected: true,
819→      continuing: true,
820→    },
821→  };
822→}
823→
824→// ---------------------------------------------------------------------------
825→// sendSessionPrompt
826→// ---------------------------------------------------------------------------
827→
828→type SendPromptInput = {
829→  surreal: Surreal;
830→  sessionId: string;
831→  text: string;
832→  adapter: SandboxAgentAdapter;
833→};
834→
835→export async function sendSessionPrompt(
836→  input: SendPromptInput,
837→): Promise<PromptSessionResult> {
838→  const lookup = await lookupSession(input.surreal, input.sessionId);
839→  if (!lookup.ok) {
840→    return { ok: false, error: lookup.error };
841→  }
842→  const { session, status } = lookup;
843→
844→  if (!PROMPTABLE_STATUSES.has(status)) {
845→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
846→    if (TERMINAL_STATUSES.has(status)) {
847→      return { ok: false, error: sessionNotFound(input.sessionId) };
848→    }
849→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
850→  }
851→
852→  if (!session.external_session_id) {
853→    return {
854→      ok: false,
855→      error: {
856→        code: "SESSION_ERROR",
857→        message: `Session ${input.sessionId} has no external_session_id — cannot deliver prompt`,
858→        httpStatus: 500,
859→      },
860→    };
861→  }
862→
863→  try {
864→    const handle = await input.adapter.resumeSession(session.external_session_id);
865→    await handle.prompt([{ type: "text", text: input.text }]);
866→    return { ok: true, value: { delivered: true } };
867→  } catch (err) {
868→    return {
869→      ok: false,
870→      error: {
871→        code: "SESSION_ERROR",
872→        message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
873→        httpStatus: 500,
874→      },
875→    };
876→  }
877→}
