 71→
 72→export type OrchestratorRouteDeps = {
 73→  createSession: (
 74→    workspaceId: string,
 75→    taskId: string,
 76→    authToken: string,
 77→    agentName?: string,
 78→  ) => Promise<OrchestratorSessionResult>;
 79→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
