 96→// ---------------------------------------------------------------------------
 97→// Request body parsing
 98→// ---------------------------------------------------------------------------
 99→
100→type AssignBody = { taskId?: string; agentId?: string };
101→type AcceptBody = { summary?: string };
102→type RejectBody = { feedback?: string };
103→type PromptBody = { text?: string };
104→
105→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
106→  try {
107→    return (await request.json()) as T;
108→  } catch {
109→    return undefined;
110→  }
111→}
112→
113→function extractAuthToken(request: Request): string {
114→  return request.headers.get("Cookie") ?? "";
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Response builders (pure)
119→// ---------------------------------------------------------------------------
120→
121→function assignResponse(
122→  workspaceId: string,
123→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
124→): Response {
125→  return jsonResponse(
126→    {
127→      agentSessionId: value.agentSessionId,
128→      streamId: value.streamId,
129→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
130→    },
131→    200,
132→  );
133→}
134→
135→function statusResponse(
136→  sessionId: string,
137→  value: {
138→    orchestratorStatus: string;
139→    worktreeBranch?: string;
140→    worktreePath?: string;
141→    startedAt?: string;
142→    lastEventAt?: string;
143→    error?: string;
144→  },
145→): Response {
146→  return jsonResponse(
147→    {
148→      agentSessionId: sessionId,
149→      orchestratorStatus: value.orchestratorStatus,
150→      ...pickDefined({
151→        worktreeBranch: value.worktreeBranch,
152→        worktreePath: value.worktreePath,
153→        startedAt: value.startedAt,
154→        lastEventAt: value.lastEventAt,
155→        error: value.error,
156→      }),
157→    },
158→    200,
159→  );
160→}
161→
162→function acceptResponse(): Response {
163→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
164→}
165→
166→function abortResponse(): Response {
167→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
168→}
169→
170→function reviewResponse(value: {
171→  taskTitle: string;
172→  diff: unknown;
173→  session: unknown;
174→}): Response {
175→  return jsonResponse(value, 200);
176→}
177→
178→function rejectResponse(): Response {
179→  return jsonResponse({ rejected: true, continuing: true }, 200);
180→}
181→
182→function promptResponse(): Response {
183→  return jsonResponse({ delivered: true }, 202);
184→}
185→
186→function sessionErrorResponse(error: {
187→  message: string;
188→  httpStatus: number;
189→}): Response {
