193→// ---------------------------------------------------------------------------
194→// Route handler factory
195→// ---------------------------------------------------------------------------
196→
197→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
198→  const assign: RouteHandler = async (request) => {
199→    const workspaceId = request.params.workspaceId;
200→    const body = await parseJsonBody<AssignBody>(request);
201→
202→    if (!body?.taskId) {
203→      return jsonError("taskId is required", 400);
204→    }
205→
206→    const authToken = extractAuthToken(request);
207→    const result = await deps.createSession(workspaceId, body.taskId, authToken, body.agentId);
208→
209→    if (!result.ok) {
210→      return sessionErrorResponse(result.error);
211→    }
212→
213→    return assignResponse(workspaceId, result.value);
214→  };
215→
216→  const status: RouteHandler = async (request) => {
217→    const sessionId = request.params.sessionId;
218→    const result = await deps.getSessionStatus(sessionId);
219→
220→    if (!result.ok) {
221→      return sessionErrorResponse(result.error);
222→    }
223→
224→    return statusResponse(sessionId, result.value);
225→  };
226→
227→  const accept: RouteHandler = async (request) => {
228→    const sessionId = request.params.sessionId;
229→    const body = await parseJsonBody<AcceptBody>(request);
230→    const summary = body?.summary ?? "";
231→
232→    const result = await deps.acceptSession(sessionId, summary);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return acceptResponse();
239→  };
240→
241→  const abort: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const result = await deps.abortSession(sessionId);
244→
245→    if (!result.ok) {
246→      return sessionErrorResponse(result.error);
247→    }
248→
249→    return abortResponse();
250→  };
251→
252→  const review: RouteHandler = async (request) => {
253→    const sessionId = request.params.sessionId;
254→    const result = await deps.getReview(sessionId);
255→
256→    if (!result.ok) {
257→      return sessionErrorResponse(result.error);
258→    }
259→
260→    return reviewResponse(result.value);
261→  };
262→
263→  const reject: RouteHandler = async (request) => {
264→    const sessionId = request.params.sessionId;
265→    const body = await parseJsonBody<RejectBody>(request);
266→
267→    if (!body?.feedback || body.feedback.trim() === "") {
268→      return jsonError("feedback is required", 400);
269→    }
270→
271→    const result = await deps.rejectSession(sessionId, body.feedback);
272→
273→    if (!result.ok) {
274→      return sessionErrorResponse(result.error);
275→    }
276→
277→    return rejectResponse();
278→  };
279→
280→  const prompt: RouteHandler = async (request) => {
281→    const sessionId = request.params.sessionId;
282→    const body = await parseJsonBody<PromptBody>(request);
283→
284→    if (!body?.text || body.text.trim() === "") {
285→      return jsonError("text is required", 400);
286→    }
287→
288→    const result = await deps.sendPrompt(sessionId, body.text);
289→
290→    if (!result.ok) {
291→      return sessionErrorResponse(result.error);
292→    }
293→
294→    return promptResponse();
295→  };
296→
297→  return { assign, status, accept, abort, review, reject, prompt };
298→}
299→
300→// ---------------------------------------------------------------------------
301→// SSE stream route handler factory
302→// ---------------------------------------------------------------------------
303→
304→export type StreamRouteDeps = {
305→  sseRegistry: SseRegistry;
306→};
307→
308→export function createStreamRouteHandler(deps: StreamRouteDeps) {
309→  const stream: RouteHandler = async (request) => {
310→    const sessionId = request.params.sessionId;
311→
312→    if (!sessionId) {
313→      return jsonError("sessionId is required", 400);
314→    }
315→
316→    const streamId = `stream-${sessionId}`;
317→    return deps.sseRegistry.handleStreamRequest(streamId);
318→  };
319→
320→  return { stream };
321→}
322→
323→// ---------------------------------------------------------------------------
324→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
325→// ---------------------------------------------------------------------------
326→
327→export type OrchestratorWiringDeps = {
328→  surreal: import("surrealdb").Surreal;
329→  shellExec: import("./worktree-manager").ShellExec;
330→  brainBaseUrl: string;
331→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
332→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
333→  sseRegistry?: SseRegistry;
334→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
335→  mockAgent: boolean;
336→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
337→  sandboxAgentType?: string;
338→  lookupAgentInWorkspace?: (
339→    surreal: import("surrealdb").Surreal,
340→    agentId: string,
341→    workspaceId: string,
342→  ) => Promise<{ name: string; runtime: string }>;
343→};
344→
345→export function wireOrchestratorRoutes(
346→  wiringDeps: OrchestratorWiringDeps,
347→): {
348→  assign: RouteHandler;
349→  status: RouteHandler;
350→  accept: RouteHandler;
351→  abort: RouteHandler;
352→  review: RouteHandler;
353→  reject: RouteHandler;
354→  prompt: RouteHandler;
355→  stream?: RouteHandler;
356→} {
357→  const proxyTokenTtlDays = readProxyTokenTtlDays();
358→
359→  const issueProxyTokenForWorkspace = async (
360→    workspaceId: string,
361→    authToken: string,
362→    opts?: { intentRecord?: RecordId<"intent", string>; sessionRecord?: RecordId<"agent_session", string> },
363→  ): Promise<{ proxyToken: string; identityId: string }> => {
364→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
365→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
366→    const personId = session?.user?.id;
367→    if (!personId) {
368→      throw new Error("Failed to issue proxy token: authentication required");
369→    }
370→
371→    const personRecord = new RecordId("person", personId);
372→    const workspaceRecord = new RecordId("workspace", workspaceId);
373→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
374→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
375→      { person: personRecord, ws: workspaceRecord },
376→    );
377→    const identityRecord = identityRows[0];
378→    if (!identityRecord) {
379→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
380→    }
381→    const identityId = identityRecord.id as string;
382→
383→    const rawToken = generateProxyToken();
384→    const tokenHash = hashProxyToken(rawToken);
385→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
386→
387→    const contentFields: Record<string, unknown> = {
388→      token_hash: tokenHash,
389→      workspace: workspaceRecord,
390→      identity: identityRecord,
391→      expires_at: expiresAt,
392→      created_at: new Date(),
393→      revoked: false,
394→    };
395→    if (opts?.intentRecord) {
396→      contentFields.intent = opts.intentRecord;
397→    }
398→    if (opts?.sessionRecord) {
399→      contentFields.session = opts.sessionRecord;
400→    }
401→
402→    await wiringDeps.surreal.query(
403→      `BEGIN TRANSACTION;
404→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
405→       CREATE proxy_token CONTENT $content;
406→       COMMIT TRANSACTION;`,
407→      {
408→        identity: identityRecord,
409→        ws: workspaceRecord,
410→        content: contentFields,
411→      },
412→    );
413→
414→    return { proxyToken: rawToken, identityId };
415→  };
416→
417→  const issueBrainMcpAuthEnv = async (
418→    workspaceId: string,
419→    identityId: string,
420→    intentGoal: string,
421→    intentReasoning: string,
422→  ): Promise<{ env: Record<string, string>; intentId: string }> => {
423→    const dpopKeys = await generateKeyPair();
424→    const intentResult = await submitIntentForAuthorization(
425→      {
426→        workspace_id: workspaceId,
427→        identity_id: identityId,
428→        authorization_details: CLI_AUTHORIZATION_DETAILS,
429→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
430→        goal: intentGoal,
431→        reasoning: intentReasoning,
432→      },
433→      {
434→        surreal: wiringDeps.surreal,
435→        extractionModel: wiringDeps.extractionModel,
436→      },
437→    );
438→
439→    let intentStatus: string = intentResult.status;
440→    if (intentStatus === "pending_auth") {
441→      const evaluation = await evaluatePendingIntent(
442→        intentResult.intentId,
443→        {
444→          surreal: wiringDeps.surreal,
445→          extractionModel: wiringDeps.extractionModel,
446→          llmEvaluator: async () => ({
447→            decision: "APPROVE",
448→            risk_score: 0,
449→            reason: "Approved from explicit authenticated orchestrator task assignment",
450→            reasoning:
451→              "User explicitly assigned this task in the orchestrator UI. " +
452→              "Bootstrap MCP token is required to complete the assigned task.",
453→          }),
454→        },
455→      );
456→      if (!evaluation.ok) {
457→        throw new Error(
458→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
459→        );
460→      }
461→      intentStatus = evaluation.value.status;
462→    }
463→
464→    if (intentStatus !== "authorized") {
465→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
466→    }
467→
468→    const tokenResult = await exchangeIntentForToken({
469→      surreal: wiringDeps.surreal,
470→      asSigningKey: wiringDeps.asSigningKey,
471→      intentId: intentResult.intentId,
472→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
473→      proofThumbprint: dpopKeys.thumbprint,
474→    });
475→
476→    if (!tokenResult.ok) {
477→      throw new Error(
478→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
479→      );
480→    }
481→
482→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
483→
484→    return {
485→      env: {
486→        BRAIN_CLIENT_ID: "orchestrator-session",
487→        BRAIN_ACCESS_TOKEN: "orchestrator-session",
488→        BRAIN_REFRESH_TOKEN: "orchestrator-session",
489→        BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
490→        BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
491→        BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
492→        BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
493→        BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
494→        BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
495→      },
496→      intentId: intentResult.intentId,
497→    };
498→  };
499→
500→  // Workspace access guard — resolves user from session cookie, checks membership
501→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
502→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
503→    if (!session?.user?.id) {
504→      return jsonError("authentication required", 401);
505→    }
506→    const { RecordId } = await import("surrealdb");
507→    const personRecord = new RecordId("person", session.user.id);
508→    const workspaceRecord = new RecordId("workspace", workspaceId);
509→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
510→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
511→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
512→      { person: personRecord, ws: workspaceRecord },
513→    );
514→    if (!memberRows || memberRows.length === 0) {
515→      return jsonError("not a member of this workspace", 403);
516→    }
517→    return undefined;
518→  };
519→
520→  // Lazy imports to keep module boundary clean
521→  const lifecycleImport = import("./session-lifecycle");
522→  const queriesImport = import("../mcp/mcp-queries");
523→  const guardImport = import("./assignment-guard");
524→  // Helper: resolve repo_path from workspace record
525→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
526→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
527→      `SELECT repo_path FROM $ws;`,
528→      { ws: workspaceRecord },
529→    );
530→    const repoPath = rows[0]?.repo_path;
531→    if (!repoPath) {
532→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
533→    }
534→    return repoPath;
535→  };
536→
537→  const buildTaskScopedIntentContext = async (
538→    taskId: string,
539→  ): Promise<{ goal: string; reasoning: string }> => {
540→    const taskRecord = new RecordId("task", taskId);
541→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
542→      `SELECT title, description FROM $task LIMIT 1;`,
543→      { task: taskRecord },
544→    );
545→    const taskTitle = taskRows[0]?.title?.trim();
546→    const taskDescription = taskRows[0]?.description?.trim();
547→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
548→    const descriptionSuffix = taskDescription && taskDescription.length > 0
549→      ? ` Task description: ${taskDescription}`
550→      : "";
551→
552→    return {
553→      goal: `Complete task: ${taskLabel}`,
554→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
555→    };
556→  };
557→
558→  // Resolve adapter: real SDK adapter from deps, or mock for tests.
559→  // Eagerly resolved when configured; lazy rejection to avoid unhandled promise
560→  // rejections in test suites that don't exercise orchestrator routes.
561→  const resolveAdapter = (): Promise<import("./sandbox-adapter").SandboxAgentAdapter> => {
562→    if (wiringDeps.sandboxAgentAdapter) return Promise.resolve(wiringDeps.sandboxAgentAdapter);
563→    if (wiringDeps.mockAgent) return import("./sandbox-adapter").then((mod) => mod.createMockAdapter());
564→    return Promise.reject(new Error("No sandbox adapter configured — set sandboxAgentAdapter or mockAgent"));
565→  };
566→
567→  const routeDeps: OrchestratorRouteDeps = {
568→    createSession: async (workspaceId, taskId, authToken, agentId) => {
569→      // Resolve agent name from agentId (if provided)
570→      let agentName: string | undefined;
571→      if (agentId) {
572→        if (!wiringDeps.lookupAgentInWorkspace) {
573→          return {
574→            ok: false as const,
575→            error: { code: "SESSION_ERROR" as const, message: "Agent lookup not configured", httpStatus: 500 },
576→          };
577→        }
578→        try {
579→          const agentInfo = await wiringDeps.lookupAgentInWorkspace(wiringDeps.surreal, agentId, workspaceId);
580→          agentName = agentInfo.name;
581→        } catch (err) {
582→          if (err instanceof HttpError) {
583→            return {
584→              ok: false as const,
585→              error: { code: "SESSION_ERROR" as const, message: err.message, httpStatus: err.status },
586→            };
587→          }
588→          throw err;
589→        }
590→      }
591→
592→      const [adapter, lifecycle, queries, guard] = await Promise.all([
593→        resolveAdapter(),
594→        lifecycleImport,
595→        queriesImport,
596→        guardImport,
597→      ]);
598→
599→      // Build task-scoped intent context, issue MCP auth env with intent
600→      const { goal, reasoning } = await buildTaskScopedIntentContext(taskId);
601→      const { identityId } = await issueProxyTokenForWorkspace(workspaceId, authToken);
602→      const mcpAuth = await issueBrainMcpAuthEnv(workspaceId, identityId, goal, reasoning);
603→      const intentRecord = new RecordId("intent", mcpAuth.intentId);
604→
605→      // Issue a governed proxy token (revoke the ungoverned one from issueProxyTokenForWorkspace)
606→      const workspaceRecord = new RecordId("workspace", workspaceId);
607→      const identityRecord = new RecordId("identity", identityId);
608→      const rawToken = generateProxyToken();
609→      const tokenHash = hashProxyToken(rawToken);
610→      const expiresAt = computeExpiresAt(proxyTokenTtlDays);
611→
612→      // Build proxy env for the sandbox agent
613→      const proxyEnv: Record<string, string> = {
614→        ...mcpAuth.env,
615→        ANTHROPIC_BASE_URL: `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic`,
616→        ANTHROPIC_CUSTOM_HEADERS: `X-Brain-Auth: ${rawToken}`,
617→      };
618→
619→      const result = await lifecycle.createOrchestratorSession({
620→        surreal: wiringDeps.surreal,
621→        shellExec: wiringDeps.shellExec,
622→        brainBaseUrl: wiringDeps.brainBaseUrl,
623→        mcpAuthToken: rawToken,
624→        workspaceId,
625→        taskId,
626→        env: proxyEnv,
627→        validateAssignment: guard.validateAssignment,
628→        createAgentSession: queries.createAgentSession,
629→        adapter,
630→        sandboxAgentType: wiringDeps.sandboxAgentType,
631→        agentName,
632→      });
633→
634→      // After session creation, create the governed proxy token with intent + session
635→      if (result.ok) {
636→        const sessionRecord = new RecordId("agent_session", result.value.agentSessionId);
637→
638→        // Revoke the ungoverned token and create a governed one
639→        await wiringDeps.surreal.query(
640→          `UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;`,
641→          { identity: identityRecord, ws: workspaceRecord },
642→        );
643→
644→        const contentFields: Record<string, unknown> = {
645→          token_hash: tokenHash,
646→          workspace: workspaceRecord,
647→          identity: identityRecord,
648→          expires_at: expiresAt,
649→          created_at: new Date(),
650→          revoked: false,
651→          intent: intentRecord,
652→          session: sessionRecord,
653→        };
654→
655→        await wiringDeps.surreal.query(
656→          `CREATE proxy_token CONTENT $content;`,
657→          { content: contentFields },
658→        );
659→      }
660→
661→      // Wire SSE stream + bootstrap prompt on success
662→      if (!result.ok) {
663→        return result;
664→      }
665→
666→      const { agentSessionId, streamId, sessionHandle } = result.value;
667→      const sessionRecord = new RecordId("agent_session", agentSessionId);
668→      const sseRegistry = wiringDeps.sseRegistry;
669→      let emittedActiveStatus = false;
670→      let observedAgentEvent = false;
671→      if (!sessionHandle) {
672→        const cleanup = await lifecycle.abortOrchestratorSession({
673→          surreal: wiringDeps.surreal,
674→          shellExec: wiringDeps.shellExec,
675→          resolveRepoRoot,
676→          sessionId: agentSessionId,
677→          adapter,
678→          endAgentSession: queries.endAgentSession,
679→        });
680→        if (!cleanup.ok) {
681→          log.warn("orchestrator.assign", "Failed to clean up session after missing session handle", {
682→            sessionId: agentSessionId,
683→            error: cleanup.error.message,
684→          });
685→        }
686→        return {
687→          ok: false,
688→          error: {
689→            code: "SESSION_ERROR",
690→            message: `Session ${agentSessionId} was created without a handle - bootstrap failed`,
691→            httpStatus: 500,
692→          },
693→        };
694→      }
695→
696→      if (sseRegistry) {
697→        sseRegistry.registerMessage(streamId);
698→
699→        const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
700→
701→        const bridge = createSandboxEventBridge(
702→          {
703→            emitEvent: sseRegistry.emitEvent,
704→            updateLastEventAt: async (sid) => {
705→              const rec = new RecordId("agent_session", sid);
706→              await wiringDeps.surreal.update(rec).merge({
707→                last_event_at: new Date(),
708→              });
709→            },
710→            updateSessionStatus: async (sid, status, error) => {
711→              const rec = new RecordId("agent_session", sid);
712→              await wiringDeps.surreal.update(rec).merge({
713→                orchestrator_status: status,
714→                last_event_at: new Date(),
715→                ...(error !== undefined ? { error_message: error } : {}),
716→              });
717→            },
718→            notifyStallDetector: () => {
719→              // Stall detector integration deferred to later step
720→            },
721→          },
722→          streamId,
723→          agentSessionId,
724→        );
725→
726→        sessionHandle.onEvent((event) => {
727→          if (event.sender === "agent") {
728→            observedAgentEvent = true;
729→          }
730→          if (!emittedActiveStatus && event.sender === "agent") {
731→            emittedActiveStatus = true;
732→            sseRegistry.emitEvent(streamId, {
733→              type: "agent_status",
734→              sessionId: agentSessionId,
735→              status: "active",
736→            });
737→            wiringDeps.surreal.update(sessionRecord).merge({
738→              orchestrator_status: "active",
739→              last_event_at: new Date(),
740→            }).catch((err) => {
741→              log.warn("orchestrator.assign", "Failed to mark session active after first event", {
742→                sessionId: agentSessionId,
743→                error: String(err),
744→              });
745→            });
746→          }
747→          bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
748→        });
749→      }
750→
751→      if (!emittedActiveStatus) {
752→        emittedActiveStatus = true;
753→        if (sseRegistry) {
754→          sseRegistry.emitEvent(streamId, {
755→            type: "agent_status",
756→            sessionId: agentSessionId,
757→            status: "active",
758→          });
759→        }
760→      }
761→      await wiringDeps.surreal.update(sessionRecord).merge({
762→        orchestrator_status: "active",
763→        last_event_at: new Date(),
764→      });
765→
766→      const initialTaskPrompt = `/brain-start-task ${taskId}`;
767→      try {
768→        await sessionHandle.prompt([{ type: "text", text: initialTaskPrompt }]);
769→        if (!observedAgentEvent) {
770→          if (sseRegistry) {
771→            sseRegistry.emitEvent(streamId, {
772→              type: "agent_status",
773→              sessionId: agentSessionId,
774→              status: "idle",
775→            });
776→          }
777→          await wiringDeps.surreal.update(sessionRecord).merge({
778→            orchestrator_status: "idle",
779→            last_event_at: new Date(),
780→          });
781→        }
782→      } catch (err) {
783→        const cleanup = await lifecycle.abortOrchestratorSession({
784→          surreal: wiringDeps.surreal,
785→          shellExec: wiringDeps.shellExec,
786→          resolveRepoRoot,
787→          sessionId: agentSessionId,
788→          adapter,
789→          endAgentSession: queries.endAgentSession,
790→        });
791→        if (!cleanup.ok) {
792→          log.warn("orchestrator.assign", "Failed to clean up session after initial prompt failure", {
793→            sessionId: agentSessionId,
794→            error: cleanup.error.message,
795→          });
796→        }
797→        const errorMessage = err instanceof Error ? err.message : String(err);
798→        return {
799→          ok: false,
800→          error: {
801→            code: "SESSION_ERROR",
802→            message: `Failed to start task session: ${errorMessage}`,
803→            httpStatus: 500,
804→          },
805→        };
806→      }
807→
808→      return result;
809→    },
810→
811→    getSessionStatus: async (sessionId) => {
812→      const lifecycle = await lifecycleImport;
813→      return lifecycle.getOrchestratorSessionStatus({
814→        surreal: wiringDeps.surreal,
815→        sessionId,
816→      });
817→    },
818→
819→    abortSession: async (sessionId) => {
820→      const [adapter, lifecycle, queries] = await Promise.all([
821→        resolveAdapter().catch(() => undefined),
822→        lifecycleImport,
823→        queriesImport,
824→      ]);
825→      return lifecycle.abortOrchestratorSession({
826→        surreal: wiringDeps.surreal,
827→        shellExec: wiringDeps.shellExec,
828→        resolveRepoRoot,
829→        sessionId,
830→        adapter,
831→        endAgentSession: queries.endAgentSession,
832→      });
833→    },
834→
835→    acceptSession: async (sessionId, summary) => {
836→      const [adapter, lifecycle, queries] = await Promise.all([
837→        resolveAdapter().catch(() => undefined),
838→        lifecycleImport,
839→        queriesImport,
840→      ]);
841→      return lifecycle.acceptOrchestratorSession({
842→        surreal: wiringDeps.surreal,
843→        shellExec: wiringDeps.shellExec,
844→        resolveRepoRoot,
845→        sessionId,
846→        summary,
847→        adapter,
848→        endAgentSession: queries.endAgentSession,
849→      });
850→    },
851→
852→    getReview: async (sessionId) => {
853→      const [lifecycle, worktreeManager] = await Promise.all([
854→        lifecycleImport,
855→        import("./worktree-manager"),
856→      ]);
857→      return lifecycle.getOrchestratorReview({
858→        surreal: wiringDeps.surreal,
859→        sessionId,
860→        resolveRepoRoot,
861→        getDiff: (repoRoot: string, branchName: string) =>
862→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
863→        getTaskTitle: async (taskId: string) => {
864→          const { RecordId } = await import("surrealdb");
865→          const taskRecord = new RecordId("task", taskId);
866→          const rows = (await wiringDeps.surreal.query(
867→            `SELECT title FROM $task;`,
868→            { task: taskRecord },
869→          )) as Array<Array<{ title: string }>>;
870→          return rows[0]?.[0]?.title ?? "";
871→        },
872→      });
873→    },
874→
875→    rejectSession: async (sessionId, feedback) => {
876→      const lifecycle = await lifecycleImport;
877→      return lifecycle.rejectOrchestratorSession({
878→        surreal: wiringDeps.surreal,
879→        sessionId,
880→        feedback,
881→      });
882→    },
883→
884→    sendPrompt: async (sessionId, text) => {
885→      const [adapter, lifecycle] = await Promise.all([resolveAdapter(), lifecycleImport]);
886→      return lifecycle.sendSessionPrompt({
887→        surreal: wiringDeps.surreal,
888→        sessionId,
889→        text,
890→        adapter,
891→      });
892→    },
893→  };
894→
895→  const handlers = createOrchestratorRouteHandlers(routeDeps);
896→
897→  // Wrap handler with workspace access check
898→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
899→    const workspaceId = request.params.workspaceId;
900→    if (workspaceId) {
901→      const accessError = await validateWorkspaceAccess(request, workspaceId);
902→      if (accessError) return accessError;
903→    }
904→    return handler(request);
905→  };
906→
907→  const streamHandler = wiringDeps.sseRegistry
908→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
909→    : undefined;
910→
911→  return {
912→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
913→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
914→    accept: withTracing("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
915→    abort: withTracing("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
916→    review: withTracing("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
917→    reject: withTracing("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
918→    prompt: withTracing("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
919→    ...(streamHandler
920→      ? { stream: withTracing("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
921→      : {}),
922→  };
923→}
