  1→/**
  2→ * Intent Submission with DPoP Thumbprint Binding
  3→ *
  4→ * OAuth 2.1 RAR+DPoP intent submission endpoint.
  5→ * Validates authorization_details with type "brain_action" and dpop_jwk_thumbprint,
  6→ * creates intent record, triggers evaluation pipeline.
  7→ *
  8→ * Pure validation functions + HTTP handler factory.
  9→ */
 10→
 11→import { RecordId } from "surrealdb";
 12→import type { BrainAction } from "./types";
 13→import type { ActionSpec } from "../intent/types";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { jsonError, jsonResponse } from "../http/response";
 16→import { createIntent, createTrace, updateIntentStatus } from "../intent/intent-queries";
 17→import { evaluateIntent, createLlmEvaluator } from "../intent/authorizer";
 18→import {
 19→  checkIdentityAllowed,
 20→  type LookupIdentity,
 21→  type LookupManager,
 22→} from "./identity-lifecycle";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Input Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type IntentSubmissionInput = {
 29→  workspace_id: string;
 30→  identity_id: string;
 31→  authorization_details: BrainAction[];
 32→  dpop_jwk_thumbprint: string;
 33→  goal: string;
 34→  reasoning: string;
 35→  priority?: number;
 36→};
 37→
 38→type ValidationResult =
 39→  | { valid: true; data: IntentSubmissionInput }
 40→  | { valid: false; error: string };
 41→
 42→// ---------------------------------------------------------------------------
 43→// Pure Validation
 44→// ---------------------------------------------------------------------------
 45→
 46→const LOW_RISK_ACTIONS = new Set(["read", "list", "get", "search", "query"]);
 47→
 48→export function validateIntentSubmission(input: unknown): ValidationResult {
 49→  if (!input || typeof input !== "object") {
 50→    return { valid: false, error: "Request body must be a non-null object" };
 51→  }
 52→
 53→  const body = input as Record<string, unknown>;
 54→
 55→  // Required string fields
 56→  const requiredStrings = ["workspace_id", "identity_id", "goal", "reasoning"] as const;
 57→  for (const field of requiredStrings) {
 58→    if (typeof body[field] !== "string" || (body[field] as string).trim().length === 0) {
 59→      return { valid: false, error: `${field} is required and must be a non-empty string` };
 60→    }
 61→  }
 62→
 63→  // dpop_jwk_thumbprint
 64→  if (typeof body.dpop_jwk_thumbprint !== "string" || (body.dpop_jwk_thumbprint as string).trim().length === 0) {
 65→    return { valid: false, error: "dpop_jwk_thumbprint is required and must be a non-empty string" };
 66→  }
 67→
 68→  // authorization_details
 69→  if (!Array.isArray(body.authorization_details)) {
 70→    return { valid: false, error: "authorization_details is required and must be an array" };
 71→  }
 72→
 73→  if (body.authorization_details.length === 0) {
 74→    return { valid: false, error: "authorization_details must contain at least one entry" };
 75→  }
 76→
 77→  for (let i = 0; i < body.authorization_details.length; i++) {
 78→    const entry = body.authorization_details[i] as Record<string, unknown>;
 79→    const validationError = validateBrainActionEntry(entry, i);
 80→    if (validationError) {
 81→      return { valid: false, error: validationError };
 82→    }
 83→  }
 84→
 85→  // Optional priority
 86→  const priority = typeof body.priority === "number" ? body.priority : undefined;
 87→
 88→  return {
 89→    valid: true,
 90→    data: {
 91→      workspace_id: (body.workspace_id as string).trim(),
 92→      identity_id: (body.identity_id as string).trim(),
 93→      authorization_details: body.authorization_details as BrainAction[],
 94→      dpop_jwk_thumbprint: (body.dpop_jwk_thumbprint as string).trim(),
 95→      goal: (body.goal as string).trim(),
 96→      reasoning: (body.reasoning as string).trim(),
 97→      ...(priority !== undefined ? { priority } : {}),
 98→    },
 99→  };
100→}
101→
102→export function validateBrainActionEntry(entry: Record<string, unknown>, index: number): string | undefined {
103→  if (!entry || typeof entry !== "object") {
104→    return `authorization_details[${index}] must be an object`;
105→  }
106→
107→  if (entry.type !== "brain_action") {
108→    return `authorization_details[${index}].type must be "brain_action"`;
109→  }
110→
111→  if (typeof entry.action !== "string" || entry.action.trim().length === 0) {
112→    return `authorization_details[${index}].action is required and must be a non-empty string`;
113→  }
114→
115→  if (typeof entry.resource !== "string" || entry.resource.trim().length === 0) {
116→    return `authorization_details[${index}].resource is required and must be a non-empty string`;
117→  }
118→
119→  return undefined;
120→}
121→
122→// ---------------------------------------------------------------------------
123→// Pure Transformations
124→// ---------------------------------------------------------------------------
125→
126→/** Derive backward-compatible ActionSpec from first BrainAction */
127→export function deriveActionSpec(actions: BrainAction[]): ActionSpec {
128→  const first = actions[0];
129→  return {
130→    provider: "brain",
131→    action: first.action,
132→    params: { resource: first.resource },
133→  };
134→}
135→
136→/** Check if all actions are low-risk read operations */
137→export function isLowRiskReadAction(actions: BrainAction[]): boolean {
138→  return actions.every((a) => LOW_RISK_ACTIONS.has(a.action.toLowerCase()));
139→}
