357→import type { Surreal } from "surrealdb";
358→import type { ResolvedIdentity, ResolvedManager } from "./identity-lifecycle";
359→import { log } from "../telemetry/logger";
360→
361→type SurrealIdentityRow = {
362→  identityId: string;
363→  identityType: string;
364→  identityStatus?: string;
365→  managedBy?: string;
366→  revokedAt?: string;
367→};
368→
369→export function createSurrealIdentityLookup(surreal: Surreal): LookupIdentity {
370→  return async (identityId: string) => {
371→    const rows = await surreal.query<[SurrealIdentityRow[]]>(
372→      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
373→      { identity: new RecordId("identity", identityId) },
374→    );
375→
376→    const row = rows[0]?.[0];
377→    if (!row) return undefined;
378→
379→    return {
380→      identityId: row.identityId,
381→      identityType: row.identityType as ResolvedIdentity["identityType"],
382→      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
383→      managedBy: row.managedBy,
384→      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
385→    };
386→  };
387→}
388→
389→export function createSurrealManagerLookup(surreal: Surreal): LookupManager {
390→  return async (managerId: string) => {
391→    // Manager ID stored as raw string reference; look up identity by searching
392→    const rows = await surreal.query<[Array<{ identityStatus?: string }>]>(
393→      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
394→      { managerId },
395→    );
396→
397→    const row = rows[0]?.[0];
398→    if (!row) return undefined;
399→
400→    return {
401→      identityId: managerId,
402→      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
403→    };
404→  };
405→}
