  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  3→import type { LlmEvaluator } from "./authorizer";
  4→import { stripRecordIdEscaping } from "../graph/record-id";
  5→import {
  6→  updateIntentStatus,
  7→  getIntentById,
  8→  countConfirmedDecisions,
  9→  countCompletedTasks,
 10→  transitionEnforcementToHard,
 11→  transitionEnforcementToSoft,
 12→} from "./intent-queries";
 13→import { shouldTransitionToHardEnforcement, shouldTransitionToSoftEnforcement } from "./maturity-transition";
 14→import { routeByRisk } from "./risk-router";
 15→import type { IntentRecord, EvaluationResult } from "./types";
 16→import type { EvidenceEnforcementMode } from "./evidence-types";
 17→import type { ServerDependencies } from "../runtime/types";
 18→import {
 19→  findAlignedObjectivesSurreal,
 20→  createSupportsEdgeSurreal,
 21→  createAlignmentWarningObservation,
 22→} from "../objective/alignment-adapter";
 23→
 24→type EvaluatePendingIntentDeps = {
 25→  surreal: Surreal;
 26→  extractionModel?: ServerDependencies["extractionModel"];
 27→  llmEvaluator?: LlmEvaluator;
 28→};
 29→
 30→type EvaluatedStatus = "authorized" | "pending_veto" | "vetoed";
 31→
 32→type EvaluatedIntent = {
 33→  intentId: string;
 34→  status: EvaluatedStatus;
 35→  evaluation: EvaluationResult & {
 36→    evaluated_at: Date;
 37→    policy_only: boolean;
 38→    policy_trace?: import("../policy/types").PolicyTraceEntry[];
 39→    human_veto_required?: boolean;
 40→  };
 41→  vetoExpiresAt?: Date;
 42→};
 43→
 44→type EvaluatePendingIntentResult =
 45→  | { ok: true; value: EvaluatedIntent }
 46→  | { ok: false; error: string; httpStatus: number };
 47→
 48→type EvaluatePendingIntentOptions = {
 49→  intent?: IntentRecord;
 50→};
 51→
 52→/**
 53→ * Resolves a record reference to a typed RecordId.
 54→ *
 55→ * Handles three input shapes:
 56→ * 1. RecordId object (SDK response) -- extracts .id directly
 57→ * 2. String "table:\`uuid\`" (SurrealDB EVENT webhook serialization) -- strips
 58→ *    table prefix and backtick/angle-bracket escaping
 59→ * 3. Plain string UUID -- used as-is
 60→ */
 61→function resolveRecordId<T extends string>(
 62→  table: T,
 63→  ref: unknown,
 64→): RecordId<T> {
 65→  if (typeof ref === "object" && ref !== null) {
 66→    return new RecordId(table, (ref as { id: unknown }).id as string);
 67→  }
 68→  const s = String(ref);
 69→  // Strip table prefix if present (e.g. "identity:`uuid`" -> "`uuid`")
 70→  const colonIdx = s.indexOf(":");
 71→  const afterPrefix = colonIdx >= 0 ? s.slice(colonIdx + 1) : s;
 72→  return new RecordId(table, stripRecordIdEscaping(afterPrefix));
 73→}
 74→
 75→type TransitionPlan = {
 76→  status: EvaluatedStatus;
 77→  updateFields: Record<string, unknown>;
 78→  vetoExpiresAt?: Date;
 79→};
 80→
 81→function toTransition(
 82→  routing: ReturnType<typeof routeByRisk>,
 83→  evaluationRecord: EvaluatedIntent["evaluation"],
 84→): TransitionPlan {
 85→  switch (routing.route) {
 86→    case "auto_approve":
 87→      return {
 88→        status: "authorized",
 89→        updateFields: { evaluation: evaluationRecord },
 90→      };
 91→    case "veto_window":
 92→      return {
 93→        status: "pending_veto",
 94→        updateFields: { evaluation: evaluationRecord, veto_expires_at: routing.expires_at },
 95→        vetoExpiresAt: routing.expires_at,
 96→      };
 97→    case "reject":
 98→      return {
 99→        status: "vetoed",
100→        updateFields: { evaluation: evaluationRecord },
101→      };
102→  }
103→}
104→
105→export async function evaluatePendingIntent(
106→  intentId: string,
107→  deps: EvaluatePendingIntentDeps,
108→  options?: EvaluatePendingIntentOptions,
109→): Promise<EvaluatePendingIntentResult> {
110→  const intent = options?.intent ?? await getIntentById(deps.surreal, intentId);
111→  if (!intent) {
112→    return { ok: false, error: "Intent not found", httpStatus: 404 };
113→  }
114→
115→  if (intent.status !== "pending_auth") {
116→    return {
117→      ok: false,
118→      error: `Intent is in '${intent.status}' status, expected 'pending_auth'`,
119→      httpStatus: 409,
120→    };
121→  }
122→
123→  const identityId = resolveRecordId("identity", intent.requester);
124→  const workspaceRecord = resolveRecordId("workspace", intent.workspace);
125→  const intentRecord = new RecordId("intent", intentId);
126→
127→  const [identityRows] = await deps.surreal.query<[Array<{ type?: string; role?: string; name?: string }>]>(
128→    `SELECT type, role, name FROM $identity;`,
129→    { identity: identityId },
130→  );
131→  const identityInfo = identityRows[0];
132→
133→  const llmEvaluator = deps.llmEvaluator
134→    ?? (deps.extractionModel ? createLlmEvaluator(deps.extractionModel) : undefined);
135→  if (!llmEvaluator) {
136→    return { ok: false, error: "Missing evaluator model", httpStatus: 500 };
137→  }
138→
139→  // Read workspace evidence enforcement mode, minimum evidence age, and maturity threshold
140→  let evidenceEnforcementMode: EvidenceEnforcementMode = "bootstrap";
141→  let minEvidenceAgeMinutes: number | undefined;
142→  try {
143→    const [wsRows] = await deps.surreal.query<[Array<{
144→      evidence_enforcement?: string;
145→      min_evidence_age_minutes?: number;
146→      evidence_enforcement_threshold?: { min_decisions?: number; min_tasks?: number };
147→    }>]>(
148→      `SELECT evidence_enforcement, min_evidence_age_minutes, evidence_enforcement_threshold FROM $ws;`,
149→      { ws: workspaceRecord },
150→    );
151→    evidenceEnforcementMode =
152→      (wsRows[0]?.evidence_enforcement as EvidenceEnforcementMode) ?? "bootstrap";
153→    minEvidenceAgeMinutes = wsRows[0]?.min_evidence_age_minutes;
154→
155→    // Lazy maturity evaluation (WD-08): check if bootstrap -> soft transition is warranted
156→    if (evidenceEnforcementMode === "bootstrap") {
157→      const confirmedDecisionCount = await countConfirmedDecisions(deps.surreal, workspaceRecord);
158→      if (shouldTransitionToSoftEnforcement({
159→        currentMode: evidenceEnforcementMode,
160→        confirmedDecisionCount,
161→      })) {
162→        const transitioned = await transitionEnforcementToSoft(deps.surreal, workspaceRecord);
163→        if (transitioned) {
164→          evidenceEnforcementMode = "soft";
165→        }
166→      }
167→    }
168→
169→    // Lazy maturity evaluation (WD-08): check if soft -> hard transition is warranted
170→    const threshold = wsRows[0]?.evidence_enforcement_threshold;
171→    if (evidenceEnforcementMode === "soft" && threshold?.min_decisions !== undefined && threshold?.min_tasks !== undefined) {
172→      const [confirmedDecisionCount, completedTaskCount] = await Promise.all([
173→        countConfirmedDecisions(deps.surreal, workspaceRecord),
174→        countCompletedTasks(deps.surreal, workspaceRecord),
175→      ]);
176→
177→      if (shouldTransitionToHardEnforcement({
178→        currentMode: evidenceEnforcementMode,
179→        confirmedDecisionCount,
180→        completedTaskCount,
181→        threshold: { min_decisions: threshold.min_decisions, min_tasks: threshold.min_tasks },
182→      })) {
183→        const transitioned = await transitionEnforcementToHard(deps.surreal, workspaceRecord);
184→        if (transitioned) {
185→          evidenceEnforcementMode = "hard";
186→        }
187→      }
188→    }
189→  } catch {
190→    // Default to bootstrap if enforcement mode cannot be read
191→  }
192→
193→  const evaluation = await evaluateIntent({
194→    intent: {
195→      goal: intent.goal,
196→      reasoning: intent.reasoning,
197→      action_spec: intent.action_spec,
198→      budget_limit: intent.budget_limit,
199→      priority: intent.priority,
200→    },
201→    surreal: deps.surreal,
202→    identityId,
203→    workspaceId: workspaceRecord,
204→    requesterType: identityInfo?.type ?? "agent",
205→    requesterRole: identityInfo?.role,
206→    llmEvaluator,
207→    intentId: intentRecord,
208→    intentText: intent.goal,
209→    findAlignedObjectives: findAlignedObjectivesSurreal(deps.surreal),
210→    createSupportsEdge: createSupportsEdgeSurreal(deps.surreal),
211→    createAlignmentWarning: (ws, iId, score) =>
212→      createAlignmentWarningObservation(deps.surreal, ws, iId, score),
213→    evidenceRefs: intent.evidence_refs,
214→    evidenceEnforcementMode,
215→    intentCreatedAt: intent.created_at,
216→    requesterAgent: identityInfo?.name,
217→    minEvidenceAgeMinutes,
218→  });
219→
220→  // --- Hard enforcement rejection: transition to "failed" without LLM evaluation record ---
221→  if (evaluation.hard_enforcement_rejection) {
222→    const failResult = await updateIntentStatus(
223→      deps.surreal,
224→      intentId,
225→      "failed",
226→      {
227→        error_reason: evaluation.reason,
228→        evidence_verification: evaluation.evidence_verification,
229→      },
230→    );
231→    if (!failResult.ok) {
232→      return { ok: false, error: failResult.error, httpStatus: 409 };
233→    }
234→    return {
235→      ok: true,
236→      value: {
237→        intentId,
238→        status: "vetoed" as EvaluatedStatus, // Return type requires EvaluatedStatus but intent is "failed" in DB
239→        evaluation: {
240→          decision: evaluation.decision,
241→          risk_score: evaluation.risk_score,
242→          reason: evaluation.reason,
243→          evaluated_at: new Date(),
244→          policy_only: false,
245→        },
246→      },
247→    };
248→  }
249→
250→  // Strip `alignment` and `evidence_verification` — they are stored separately
251→  const { alignment: _alignment, evidence_verification, ...evaluationForDb } = evaluation;
252→  const evaluationRecord: EvaluatedIntent["evaluation"] = {
253→    ...evaluationForDb,
254→    evaluated_at: new Date(),
255→  };
256→  const routing = routeByRisk(evaluation, {
257→    humanVetoRequired: evaluation.human_veto_required,
258→    evidenceVerification: evidence_verification,
259→  });
260→  const transition = toTransition(routing, evaluationRecord);
261→
262→  // Include evidence_verification in the status update
263→  if (evidence_verification) {
264→    transition.updateFields.evidence_verification = evidence_verification;
265→  }
266→
267→  const result = await updateIntentStatus(
268→    deps.surreal,
269→    intentId,
270→    transition.status,
271→    transition.updateFields,
272→  );
273→  if (!result.ok) {
274→    return { ok: false, error: result.error, httpStatus: 409 };
275→  }
276→
277→  return {
278→    ok: true,
279→    value: {
280→      intentId,
281→      status: transition.status,
282→      evaluation: evaluationRecord,
283→      ...(transition.vetoExpiresAt ? { vetoExpiresAt: transition.vetoExpiresAt } : {}),
284→    },
285→  };
286→}
