 57→export const collectAndSortRules = (
 58→  policies: PolicyRecord[],
 59→): AnnotatedRule[] => {
 60→  const annotated = policies.flatMap((policy) =>
 61→    policy.rules.map((rule) => ({
 62→      policyId: policy.id.id as string,
 63→      policyVersion: policy.version,
 64→      humanVetoRequired: policy.human_veto_required,
 65→      rule,
 66→    })),
 67→  );
 68→
 69→  return annotated.sort((a, b) => b.rule.priority - a.rule.priority);
 70→};
 71→
 72→export const evaluateRulesAgainstContext = (
 73→  rules: AnnotatedRule[],
 74→  context: IntentEvaluationContext,
 75→): EvaluationResult => {
 76→  const contextRecord = context as unknown as Record<string, unknown>;
 77→  const evaluatedRules: EvaluatedRule[] = [];
 78→  const allWarnings: PolicyGateWarning[] = [];
 79→
 80→  for (const annotated of rules) {
 81→    const { matched, warnings } = evaluateCondition(
 82→      contextRecord,
 83→      annotated.rule.condition,
 84→      annotated.rule.id,
 85→      annotated.policyId,
 86→    );
 87→
 88→    allWarnings.push(...warnings);
 89→    evaluatedRules.push({ ...annotated, matched, warnings });
 90→
 91→    if (matched && annotated.rule.effect === "deny") {
 92→      return {
 93→        evaluatedRules,
 94→        denyMatched: true,
 95→        warnings: allWarnings,
 96→      };
 97→    }
 98→  }
 99→
100→  return {
101→    evaluatedRules,
102→    denyMatched: false,
103→    warnings: allWarnings,
104→  };
105→};
106→
107→/**
108→ * Extracts evidence requirements from matched evidence_requirement rules.
109→ * Returns the first (highest-priority) matched requirement, since rules
110→ * are already sorted by priority DESC.
111→ */
112→export const extractEvidenceRequirements = (
113→  evaluatedRules: EvaluatedRule[],
114→): PolicyEvidenceRequirements | undefined => {
115→  const matchedRequirement = evaluatedRules.find(
116→    (entry) =>
117→      entry.matched && entry.rule.effect === "evidence_requirement",
118→  );
119→
120→  if (!matchedRequirement) return undefined;
121→
122→  return {
123→    min_count: matchedRequirement.rule.min_evidence_count ?? 1,
124→    ...(matchedRequirement.rule.required_types
125→      ? { required_types: matchedRequirement.rule.required_types }
126→      : {}),
127→  };
128→};
129→
130→export const buildGateResult = (
131→  evaluatedRules: EvaluatedRule[],
132→  denyMatched: boolean,
133→  warnings: PolicyGateWarning[],
134→  evidenceRequirements?: PolicyEvidenceRequirements,
135→): PolicyGateResult => {
136→  const policyTrace: PolicyTraceEntry[] = evaluatedRules.map((entry) => ({
137→    policy_id: entry.policyId,
138→    policy_version: entry.policyVersion,
139→    rule_id: entry.rule.id,
140→    effect: entry.rule.effect,
141→    matched: entry.matched,
142→    priority: entry.rule.priority,
143→  }));
144→
145→  if (denyMatched) {
146→    const denyRule = evaluatedRules.find(
147→      (entry) => entry.matched && entry.rule.effect === "deny",
148→    );
149→    return {
150→      passed: false,
151→      reason: `Policy deny rule '${denyRule!.rule.id}' matched`,
152→      policy_trace: policyTrace,
153→      deny_rule_id: denyRule!.rule.id,
154→      warnings,
155→    };
156→  }
157→
158→  const humanVetoRequired = evaluatedRules.some(
159→    (entry) => entry.humanVetoRequired,
160→  );
161→
162→  return {
163→    passed: true,
164→    policy_trace: policyTrace,
165→    human_veto_required: humanVetoRequired,
166→    warnings,
167→    ...(evidenceRequirements ? { evidence_requirements: evidenceRequirements } : {}),
168→  };
169→};
