171→// ---------------------------------------------------------------------------
172→// Composition Root (single effect boundary)
173→// ---------------------------------------------------------------------------
174→
175→export const evaluatePolicyGate = async (
176→  surreal: Surreal,
177→  identityId: RecordId<"identity">,
178→  workspaceId: RecordId<"workspace">,
179→  intentContext: IntentEvaluationContext,
180→): Promise<PolicyGateResult> => {
181→  // Effect boundary: single DB read
182→  const rawPolicies = await loadActivePolicies(surreal, identityId, workspaceId);
183→
184→  // Pure pipeline
185→  const deduplicated = deduplicatePolicies(rawPolicies);
186→  const sortedRules = collectAndSortRules(deduplicated);
187→  const { evaluatedRules, denyMatched, warnings } = evaluateRulesAgainstContext(
188→    sortedRules,
189→    intentContext,
190→  );
191→  const evidenceRequirements = extractEvidenceRequirements(evaluatedRules);
192→
193→  return buildGateResult(evaluatedRules, denyMatched, warnings, evidenceRequirements);
194→};
